-- Re-seed del catálogo de deducciones (autogenerado).
--
-- Fuente: archivos supabase/seeds/renta/deductions/<CCAA>.json.
-- Regenerar con: node scripts/build-renta-seed.mjs
--
-- Idempotente: TRUNCATE limpia cualquier estado previo (seeds anteriores
-- 20260514110100 / 20260514140000 inclusive) y re-inserta el catálogo
-- completo.
--
-- NOTAS:
-- - Navarra y País Vasco NO están (régimen foral propio, no aparecen en el
--   manual estatal de la AEAT).
-- - Para deducciones con fórmulas complejas (% sobre cuota, prorrateos),
--   solo se encoda el gate básico de elegibilidad; el importe lo calcula
--   el asesor revisando la submission.
-- - Total deducciones cargadas: 349 en 15 CCAA.

TRUNCATE TABLE renta.deductions;

INSERT INTO renta.deductions (
  id, ccaa_code, title, what_covers, requirements, legal_reference,
  eligibility_rule, extra_fields, display_order, is_active
)
SELECT
  (row->>'id')::text,
  (row->>'ccaa_code')::text,
  (row->>'title')::text,
  (row->>'what_covers')::text,
  COALESCE(row->'requirements', '[]'::jsonb),
  (row->>'legal_reference')::text,
  COALESCE(row->'eligibility_rule', '{"all_of":[]}'::jsonb),
  COALESCE(row->'extra_fields', '[]'::jsonb),
  COALESCE((row->>'display_order')::int, 0),
  COALESCE((row->>'is_active')::boolean, true)
FROM jsonb_array_elements('[{"id":"and-vivienda-protegida-jovenes","ccaa_code":"ES-AN","title":"Por inversión en vivienda habitual que tenga la consideración de protegida y por las personas jóvenes","what_covers":"Cubre las cantidades satisfechas por la adquisición o rehabilitación de la vivienda habitual cuando esta tiene calificación de protegida en Andalucía o cuando el adquirente es menor de 35 años.","requirements":["Vivienda habitual en régimen de propiedad situada en Andalucía","Vivienda con calificación de protegida o adquirente menor de 35 años","Suma de bases imponibles ≤ 25.000 € (individual) / 30.000 € (conjunta)","Deducción: 6% de las cantidades satisfechas","Base máxima de deducción: 9.040 €"],"legal_reference":"Arts. 9 y 2 y disposición adicional primera Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"eq","path":"housing.type","value":"propiedad"},{"op":"eq","path":"housing.is_habitual","value":true},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":25000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":30000}]}]}]},"extra_fields":[{"key":"acquisition_or_rehab_amount_eur","label":"Cantidades satisfechas en el ejercicio por adquisición o rehabilitación (€)","kind":"number","required":true,"min":0},{"key":"housing_type","label":"Supuesto que da derecho","kind":"select","required":true,"options":[{"value":"protegida","label":"Vivienda con calificación de protegida"},{"value":"joven_menor_35","label":"Adquirente menor de 35 años"},{"value":"ambos","label":"Vivienda protegida y adquirente menor de 35 años"}]},{"key":"acquisition_date","label":"Fecha de adquisición o inicio de rehabilitación","kind":"date","required":false},{"key":"external_financing","label":"¿Existe financiación ajena (préstamo hipotecario)?","kind":"boolean","required":false}],"display_order":10,"is_active":true},{"id":"and-alquiler-vivienda-habitual","ccaa_code":"ES-AN","title":"Por cantidades invertidas en el alquiler de la vivienda habitual","what_covers":"Cubre las cantidades pagadas en concepto de alquiler de la vivienda habitual del contribuyente cuando concurre alguna circunstancia personal (edad, discapacidad, condición de víctima) que da derecho a la deducción.","requirements":["Vivienda habitual en régimen de alquiler","Ser titular del contrato de arrendamiento","Cumplir alguna circunstancia: menor de 35 años, mayor de 65, víctima de violencia doméstica o de terrorismo","Suma de bases imponibles ≤ 25.000 € (individual) / 30.000 € (conjunta)","Aportar NIF del arrendador","Deducción: 15% de las cantidades pagadas","Límite: 1.200 €/año (1.500 € si discapacidad ≥33%, o ≥65% si pre-2022)"],"legal_reference":"Arts. 10 y 2 y disposición adicional primera Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"eq","path":"housing.type","value":"alquiler"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":25000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":30000}]}]}]},"extra_fields":[{"key":"annual_rent_eur","label":"Renta anual pagada (€)","kind":"number","required":true,"min":0},{"key":"tenant_circumstance","label":"Circunstancia que da derecho","kind":"select","required":true,"options":[{"value":"menor_35","label":"Menor de 35 años a fecha de devengo"},{"value":"mayor_65","label":"Mayor de 65 años a fecha de devengo"},{"value":"victima_violencia_domestica","label":"Víctima de violencia doméstica"},{"value":"victima_terrorismo","label":"Víctima del terrorismo o persona afectada"}]},{"key":"is_disabled","label":"¿Persona con discapacidad (≥33% o ≥65%