cogimiento familiar permanente"},{"value":"guarda_preadoptiva","label":"Delegación de guarda con fines de convivencia preadoptiva"}]},{"key":"multiple_birth_or_adoption","label":"¿Parto, adopción o acogimiento múltiple?","kind":"boolean","required":false},{"key":"small_municipality","label":"¿Residencia en municipio con problemas de despoblación (<3.000 hab.)?","kind":"boolean","required":false},{"key":"no_aids_received","label":"(Acogimiento) Confirmo no haber recibido ayudas de la Junta vinculadas al acogimiento","kind":"boolean","required":false}],"display_order":30,"is_active":true},{"id":"and-adopcion-internacional","ccaa_code":"ES-AN","title":"Por adopción de hijos en el ámbito internacional","what_covers":"Cubre las adopciones de hijos formalizadas en el ámbito internacional durante el período impositivo en que se inscribe la adopción en el Registro Civil.","requirements":["Haber adoptado a uno o más hijos en el ámbito internacional","La adopción debe inscribirse en el Registro Civil en el ejercicio","Suma de bases imponibles ≤ 80.000 € (individual) / 100.000 € (conjunta)","Incompatible con la deducción por nacimiento/adopción respecto del mismo hijo","Importe: 600 € por cada hijo adoptado","Aportar resolución o certificado de adopción internacional"],"legal_reference":"Art. 12 Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"gte","path":"kids.length","value":1},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":80000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":100000}]}]}]},"extra_fields":[{"key":"international_adoption_kids","label":"Hijos adoptados internacionalmente (nombre y fecha de inscripción en Registro Civil)","kind":"textarea","required":true},{"key":"international_adoption_certificate","label":