ad participada","kind":"text","required":true},{"key":"entity_type","label":"Forma jurídica","kind":"select","required":true,"options":[{"value":"sa","label":"Sociedad Anónima"},{"value":"sl","label":"Sociedad Limitada"},{"value":"cooperativa","label":"Cooperativa"},{"value":"laboral","label":"Sociedad Laboral"}]},{"key":"operation_type","label":"Operación","kind":"select","required":true,"options":[{"value":"constitucion","label":"Constitución"},{"value":"ampliacion","label":"Ampliación de capital"}]},{"key":"participation_percentage","label":"% de participación adquirida (≤ 40% incluido entorno familiar)","kind":"number","required":false,"min":0,"max":40},{"key":"investment_date","label":"Fecha de la inversión","kind":"date","required":true}],"display_order":260,"is_active":true},{"id":"ast-enfermedad-celiaca","ccaa_code":"ES-AS","title":"Por gastos derivados de la enfermedad celíaca diagnosticada","what_covers":"Deducción de 100 € por cada miembro del núcleo familiar diagnosticado de enfermedad celíaca. Compensa el sobrecoste de la dieta sin gluten.","requirements":["Que el contribuyente, su cónyuge, ascendientes o descendientes con derecho al mínimo familiar estén diagnosticados de enfermedad celíaca","Disponer de informe médico oficial del Servicio Nacional de Salud o del aseguramiento sanitario privado","Base imponible ≤ 35.000 € en individual o ≤ 45.000 € en conjunta","Aportar parentesco y fecha de diagnóstico de cada miembro afectado"],"legal_reference":"Art. 14 novodecies Texto Refundido del Decreto Legislativo 2/2014, de 22 de octubre, del Principado de Asturias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AS"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":35000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":45000}]}]}]},"extra_fields":[{"key":"celiac_members_count","label":"Miembros del núcleo 