vel","label":"Nivel de estudios","kind":"select","required":true,"options":[{"value":"bachillerato","label":"Bachillerato"},{"value":"fp","label":"Formación Profesional"},{"value":"universitarios","label":"Universitarios"}]},{"key":"municipality","label":"Municipio de residencia (Orden PRE/1/2025)","kind":"text","required":true}],"display_order":140,"is_active":true},{"id":"ctb-residencia-despoblamiento","ccaa_code":"ES-CB","title":"Por residencia habitual en un municipio afectado por riesgo de despoblamiento","what_covers":"Deducción para contribuyentes jóvenes que residen de forma habitual durante todo el año en un municipio cántabro afectado por riesgo de despoblamiento.","requirements":["Tener menos de 40 años a la fecha de devengo del impuesto (31 de diciembre).","Residencia habitual durante todo el año natural en un municipio incluido en la Orden PRE/1/2025.","Importe: 20% de la cuota íntegra autonómica.","Límite máximo: 500 €."],"legal_reference":"Art. 2.11.5 Texto Refundido Decreto Legislativo 62/2008 de Cantabria","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CB"},{"op":"age_lt","path":"birth_date","value":40},{"op":"eq","path":"small_municipality","value":true}]},"extra_fields":[{"key":"municipality","label":"Municipio de residencia (Orden PRE/1/2025)","kind":"text","required":true},{"key":"full_year_resident","label":"Confirmo residencia habitual durante todo el año natural","kind":"boolean","required":true}],"display_order":150,"is_active":true},{"id":"ctb-inversiones-economia-social","ccaa_code":"ES-CB","title":"Por inversiones o donaciones a entidades de la Economía Social establecidas en Cantabria","what_covers":"Deducción por aportar capital o realizar donaciones a entidades de Economía Social (cooperativas, sociedades laborales, etc.) con domicilio en Cantabria.","requirements":["La entidad debe tener domicilio social en Cantabria y formar parte de la Economía Social.","Modalidades: 20% por inversión para ser socio, 50% por donación irrevocable para actividades económicas, 25% por donación para fomento/difusión de la Economía Social.","Cuando se accede como socio, la participación (con el entorno familiar) no puede superar el 40%.","Mantenimiento de la inversión o destino de la donación entre 3 y 5 años, según modalidad.","Límite conjunto: 3.000 € por contribuyente.","Aportar NIF y nombre de la entidad, modalidad e importe."],"legal_reference":"Art. 2.12 Texto Refundido Decreto Legislativo 62/2008 de Cantabria","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CB"}]},"extra_fields":[{"key":"amount_eur","label":"Importe invertido o donado en el ejercicio (€)","kind":"number","required":true,"min":0},{"key":"operation_type","label":"Modalidad","kind":"select","required":true,"options":[{"value":"inversion_socio","label":"Inversión para ser socio (20%)"},{"value":"donacion_actividad","label":"Donación para actividades económicas (50%)"},{"value":"donacion_fomento","label":"Donación para fomento y difusión de la Economía Social (25%)"}]},{"key":"entity_nif","label":"NIF de la entidad","kind":"text","required":true},{"key":"entity_name","label":"Nombre de la entidad","kind":"text","required":true},{"key":"participation_percentage","label":"% de participación (≤ 40% con entorno familiar)","kind":"number","required":false,"min":0,"max":40}],"display_order":160,"is_active":true},{"id":"ctb-gastos-educacion","ccaa_code":"ES-CB","title":"Por gastos de educación","what_covers":"Deducción para compensar los gastos de libros de texto de enseñanzas obligatorias y la enseñanza extraescolar de idiomas de los hijos durante esas etapas.","requirements":["Hijos cursando enseñanzas obligatorias (Primaria y ESO).","Libros de texto: deducción del 100% del importe pagado.","Enseñanza extraescolar de idiomas durante la etapa obligatoria: deducción del 15% del importe pagado.","Suma máxima de la deducción: 200 € por unidad familiar.","Aportar detalle por cada hijo y conservar facturas."],"legal_re