te","path":"kids.length","value":2}]},"extra_fields":[{"key":"multiple_birth_type","label":"Tipo de parto/adopción","kind":"select","required":true,"options":[{"value":"doble","label":"Parto/adopción de 2 hijos"},{"value":"triple_o_mas","label":"Parto/adopción de 3 o más hijos"},{"value":"sucesivos_12m","label":"Nacimientos/adopciones independientes en 12 meses"}]},{"key":"multiple_birth_date","label":"Fecha del parto múltiple o adopción simultánea","kind":"date","required":true},{"key":"additional_2023_2024","label":"¿Aplica deducción adicional de 901 € por parto múltiple/adopción simultánea de 2023 o 2024?","kind":"boolean","required":false},{"key":"no_bono_nacimiento","label":"Confirmo que NO se ha percibido el Bono Nacimiento por estos hijos","kind":"boolean","required":true}],"display_order":30,"is_active":true},{"id":"cyl-gastos-adopcion","ccaa_code":"ES-CL","title":"Por gastos de adopción","what_covers":"Deducción por los gastos derivados de la adopción de hijos formalizada en el ejercicio, con cuantía mayor para adopciones internacionales. Es incompatible con el Bono Nacimiento.","requirements":["Adopción realizada durante el ejercicio que dé derecho al mínimo por descendientes","Cuantías: 784 € por cada adopción; 3.625 € si es adopción internacional","Aplicable en el ejercicio en que se produzca la inscripción en el Registro Civil","Indicar número de adopciones, fecha de inscripción y datos del menor","No haber percibido el Bono Nacimiento por ese hijo (incompatible)"],"legal_reference":"Arts. 4.5 y 10 Texto Refundido Decreto Legislativo 1/2013 de Castilla y León","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CL"},{"op":"gte","path":"kids.length","value":1}]},"extra_fields":[{"key":"adoption_count","label":"Número de adopciones en el ejercicio","kind":"number","required":true,"min":1},{"key":"international_adoption","label":"¿Adopción internacional?","kind":"boolean","required":false},{"key":"registry_date","label":"Fecha de inscripción